from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    sentences = []
    for subject, triples in subject_map.items():
        base = f"{subject}"
        details = []
        runway_info = []
        elevation_info = []
        location_info = []
        identifier_info = []
        other_info = []

        for predicate, obj in triples:
            if predicate == "cityServed":
                location_info.append(f"serves {obj}")
            elif predicate == "country":
                location_info.append(f"is in {obj}")
            elif predicate == "capital":
                location_info.append(f"has {obj} as its capital")
            elif predicate == "isPartOf":
                location_info.append(f"is part of {obj}")
            elif predicate == "location":
                location_info.append(f"is located in {obj}")
            elif predicate == "elevationAboveTheSeaLevel":
                elevation_info.append(f"has an elevation of {obj} metres above sea level")
            elif predicate == "elevationAboveTheSeaLevelInFeet":
                elevation_info.append(f"has an elevation of {obj} feet above sea level")
            elif predicate == "runwayLength":
                runway_info.append(f"has a runway length of {obj} metres")
            elif predicate == "runwayName":
                runway_info.append(f"has a runway named {obj}")
            elif predicate == "runwaySurfaceType":
                runway_info.append(f"has a runway surface type of {obj}")
            elif predicate == "1stRunwayLengthFeet":
                runway_info.append(f"has a first runway of {obj} feet")
            elif predicate == "1stRunwaySurfaceType":
                runway_info.append(f"has a first runway made of {obj}")
            elif predicate == "2ndRunwaySurfaceType":
                runway_info.append(f"has a second runway made of {obj}")
            elif predicate == "3rdRunwayLengthFeet":
                runway_info.append(f"has a third runway of {obj} feet")
            elif predicate == "3rdRunwaySurfaceType":
                runway_info.append(f"has a third runway made of {obj}")
            elif predicate == "icaoLocationIdentifier":
                identifier_info.append(f"has an ICAO code of {obj}")
            elif predicate == "iataLocationIdentifier":
                identifier_info.append(f"has an IATA code of {obj}")
            elif predicate == "locationIdentifier":
                identifier_info.append(f"has a location code of {obj}")
            elif predicate == "nativeName":
                details.append(f"is also known as {obj}")
            elif predicate == "operatingOrganisation":
                details.append(f"is operated by {obj}")
            elif predicate == "owner":
                details.append(f"is owned by {obj}")
            elif predicate == "mayor":
                details.append(f"has a mayor named {obj}")
            elif predicate == "language":
                details.append(f"has {obj} as its language")
            elif predicate == "leader":
                details.append(f"has {obj} as its leader")
            elif predicate == "leaderParty":
                details.append(f"has {obj} as its ruling party")
            elif predicate == "officialLanguage":
                details.append(f"has {obj} as its official language")
            else:
                other_info.append(f"has a {predicate.replace('1stRunway', 'first runway').replace('2ndRunway', 'second runway').replace('3rdRunway', 'third runway').replace('4thRunway', 'fourth runway').replace('5thRunway', 'fifth runway')} of {obj}")

        # Build the sentence with logical grouping
        if location_info:
            base += " " + ", ".join(location_info)
        if elevation_info:
            base += " " + ", ".join(elevation_info)
        if runway_info:
            # Combine runway info into one coherent phrase
            base += " " + " and ".join(runway_info)
        if identifier_info:
            base += " " + ", ".join(identifier_info)
        if details:
            base += " " + ", ".join(details)
        if other_info:
            base += " " + ", ".join(other_info)

        sentences.append(base)

    # Join multiple subjects with "and" if needed
    if len(sentences) > 1:
        return " and ".join(sentences) + "."
    else:
        return sentences[0] + "."

